import type { NextRequest } from "next/server"
import { NextResponse } from "next/server"
import { configValidationMiddleware } from "@/lib/middleware/config-validation"
import { rateLimitMiddleware, getClientIP } from "@/lib/rate-limiting/middleware"

const SESSION_COOKIE_NAME = "firebaseSession"

export async function middleware(request: NextRequest) {
  // First, validate configuration
  const configResponse = await configValidationMiddleware(request)
  if (configResponse.status !== 200) {
    return configResponse
  }
  
  // Apply rate limiting to API routes
  if (request.nextUrl.pathname.startsWith("/api/")) {
    const sessionCookie = request.cookies.get(SESSION_COOKIE_NAME)?.value
    let userId: string | undefined
    let subscriptionPlan: string | undefined
    
    // Extract user info from session if available
    if (sessionCookie) {
      // In a real implementation, decode the session to get user info
      // For now, use headers as fallback
      userId = request.headers.get('x-user-id') || undefined
      subscriptionPlan = request.headers.get('x-subscription-plan') || 'free'
    }
    
    const rateLimitResponse = await rateLimitMiddleware(request, {
      userId,
      subscriptionPlan,
      ipAddress: getClientIP(request),
      endpoint: request.nextUrl.pathname,
    })
    
    if (rateLimitResponse) {
      return rateLimitResponse
    }
  }
  
  // Then proceed with authentication middleware
  const sessionCookie = request.cookies.get(SESSION_COOKIE_NAME)?.value
  const isAuthenticated = Boolean(sessionCookie)

  const { pathname } = request.nextUrl

  if (!isAuthenticated && pathname.startsWith("/dashboard")) {
    const url = request.nextUrl.clone()
    url.pathname = "/auth/login"
    return NextResponse.redirect(url)
  }

  if (isAuthenticated && pathname.startsWith("/auth/")) {
    const url = request.nextUrl.clone()
    url.pathname = "/dashboard"
    return NextResponse.redirect(url)
  }

  return NextResponse.next()
}

export const config = {
  matcher: ["/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp)$).*)"],
}
